    input  logic [9:0] SW,
    input  logic [9:0] h_count,
    input  logic [9:0] v_count,
    input  logic       video_on,
    input  logic       frame_tick,
    output logic [7:0] VGA_R,
    output logic [7:0] VGA_G,
    output logic [7:0] VGA_B
);

    logic btn_right, btn_left, btn_down, btn_up;

    vga_input_decoder u_input_decoder (
        .KEY(KEY),
        .btn_right(btn_right),
        .btn_left(btn_left),
        .btn_down(btn_down),
        .btn_up(btn_up)
    );

    vga_sw_edge_detector u_sw8_edge (
        .clk(clk_25M),
        .reset(real_reset),
        .sw_in(SW[8]),
        .edge_pulse(sw8_edge)
    );

    parameter SQUARE_SIZE = 20;
    parameter STEP        = 1;


    localparam TIMER_MAX = 10'd999;
    localparam DIGIT_W = 10'd24;
    localparam DIGIT_H = 10'd48;
    localparam SEG_T = 10'd4;
    localparam D0_X = 10'd540;
    localparam D1_X = 10'd568;
    localparam D2_X = 10'd596;
    localparam D_Y  = 10'd20;
    localparam TINY_DIGIT_W = 10'd10;
    localparam TINY_DIGIT_H = 10'd16;
    localparam TINY_SEG_T = 10'd2;

    function automatic logic [6:0] seg_map(input logic [3:0] digit);
        begin
            case (digit)
                4'd0: seg_map = 7'b1111110;
                4'd1: seg_map = 7'b0110000;
                4'd2: seg_map = 7'b1101101;
                4'd3: seg_map = 7'b1111001;
                4'd4: seg_map = 7'b0110011;
                4'd5: seg_map = 7'b1011011;
                4'd6: seg_map = 7'b1011111;
                4'd7: seg_map = 7'b1110000;
                4'd8: seg_map = 7'b1111111;
                4'd9: seg_map = 7'b1111011;
                default: seg_map = 7'b0000000;
            endcase
        end
    endfunction

    function automatic logic digit_pixel_fn(
        input logic [9:0] px,
        input logic [9:0] py,
        input logic [9:0] ox,
        input logic [9:0] oy,
        input logic [3:0] digit
    );
        logic [6:0] seg;
        begin
            seg = seg_map(digit);
            digit_pixel_fn = 1'b0;

            if (px >= ox && px < ox + DIGIT_W && py >= oy && py < oy + DIGIT_H) begin
                if (seg[6] &&
                    py >= oy && py < oy + SEG_T &&
                    px >= ox + SEG_T && px < ox + DIGIT_W - SEG_T)
                    digit_pixel_fn = 1'b1;
                else if (seg[5] &&
                         px >= ox + DIGIT_W - SEG_T && px < ox + DIGIT_W &&
                         py >= oy + SEG_T && py < oy + (DIGIT_H >> 1) - 1)
                    digit_pixel_fn = 1'b1;
                else if (seg[4] &&
                         px >= ox + DIGIT_W - SEG_T && px < ox + DIGIT_W &&
                         py >= oy + (DIGIT_H >> 1) + 1 && py < oy + DIGIT_H - SEG_T)
                    digit_pixel_fn = 1'b1;
                else if (seg[3] &&
                         py >= oy + DIGIT_H - SEG_T && py < oy + DIGIT_H &&
                         px >= ox + SEG_T && px < ox + DIGIT_W - SEG_T)
                    digit_pixel_fn = 1'b1;
                else if (seg[2] &&
                         px >= ox && px < ox + SEG_T &&
                         py >= oy + (DIGIT_H >> 1) + 1 && py < oy + DIGIT_H - SEG_T)
                    digit_pixel_fn = 1'b1;
                else if (seg[1] &&
                         px >= ox && px < ox + SEG_T &&
                         py >= oy + SEG_T && py < oy + (DIGIT_H >> 1) - 1)
                    digit_pixel_fn = 1'b1;
                else if (seg[0] &&
                         py >= oy + (DIGIT_H >> 1) - (SEG_T >> 1) &&
                         py < oy + (DIGIT_H >> 1) + ((SEG_T + 1) >> 1) &&
                         px >= ox + SEG_T && px < ox + DIGIT_W - SEG_T)
                    digit_pixel_fn = 1'b1;
            end
        end
    endfunction


    function automatic logic tiny_digit_pixel_fn(
        input logic [9:0] px,
        input logic [9:0] py,
        input logic [9:0] ox,
        input logic [9:0] oy,
        input logic [3:0] digit
    );
        logic [6:0] seg;
        begin
            seg = seg_map(digit);
            tiny_digit_pixel_fn = 1'b0;

            if (px >= ox && px < ox + TINY_DIGIT_W && py >= oy && py < oy + TINY_DIGIT_H) begin
                if (seg[6] &&
                    py >= oy && py < oy + TINY_SEG_T &&
                    px >= ox + TINY_SEG_T && px < ox + TINY_DIGIT_W - TINY_SEG_T)
                    tiny_digit_pixel_fn = 1'b1;
                else if (seg[5] &&
                         px >= ox + TINY_DIGIT_W - TINY_SEG_T && px < ox + TINY_DIGIT_W &&
                         py >= oy + TINY_SEG_T && py < oy + (TINY_DIGIT_H >> 1) - 1)
                    tiny_digit_pixel_fn = 1'b1;
                else if (seg[4] &&
                         px >= ox + TINY_DIGIT_W - TINY_SEG_T && px < ox + TINY_DIGIT_W &&
                         py >= oy + (TINY_DIGIT_H >> 1) + 1 && py < oy + TINY_DIGIT_H - TINY_SEG_T)
                    tiny_digit_pixel_fn = 1'b1;
                else if (seg[3] &&
                         py >= oy + TINY_DIGIT_H - TINY_SEG_T && py < oy + TINY_DIGIT_H &&
                         px >= ox + TINY_SEG_T && px < ox + TINY_DIGIT_W - TINY_SEG_T)
                    tiny_digit_pixel_fn = 1'b1;
                else if (seg[2] &&
                         px >= ox && px < ox + TINY_SEG_T &&
                         py >= oy + (TINY_DIGIT_H >> 1) + 1 && py < oy + TINY_DIGIT_H - TINY_SEG_T)
                    tiny_digit_pixel_fn = 1'b1;
                else if (seg[1] &&
                         px >= ox && px < ox + TINY_SEG_T &&
                         py >= oy + TINY_SEG_T && py < oy + (TINY_DIGIT_H >> 1) - 1)
                    tiny_digit_pixel_fn = 1'b1;
                else if (seg[0] &&
                         py >= oy + (TINY_DIGIT_H >> 1) - (TINY_SEG_T >> 1) &&
                         py < oy + (TINY_DIGIT_H >> 1) + ((TINY_SEG_T + 1) >> 1) &&
                         px >= ox + TINY_SEG_T && px < ox + TINY_DIGIT_W - TINY_SEG_T)
                    tiny_digit_pixel_fn = 1'b1;
            end
        end
    endfunction

    function automatic logic rect_hit(
        input logic [9:0] sx,
        input logic [9:0] sy,
        input logic [9:0] rx1,
        input logic [9:0] rx2,
        input logic [9:0] ry1,
        input logic [9:0] ry2
    );
        begin
            rect_hit =
                (sx + SQUARE_SIZE - 10'd1 >= rx1) &&
                (sx <= rx2) &&
                (sy + SQUARE_SIZE - 10'd1 >= ry1) &&
                (sy <= ry2);
        end
    endfunction

