    function automatic logic end_text_line_pixel(
        input logic [9:0] px,
        input logic [9:0] py,
        input logic [9:0] x0,
        input logic [9:0] y0,
        input logic [1:0] line_id,
        input logic [4:0] line_len
    );
        integer ix;
        integer iy;
        integer char_idx;
        integer char_col;
        integer char_row;
        logic [7:0] ch;
        logic [4:0] bits;
        begin
            end_text_line_pixel = 1'b0;
            if ((px >= x0) && (py >= y0)) begin
                ix = px - x0;
                iy = py - y0;
                if (iy < 21) begin
                    char_idx = ix / 18;
                    char_col = (ix % 18) / 3;
                    char_row = iy / 3;
                    if ((char_idx < line_len) && (char_col < 5) && (char_row < 7)) begin
                        ch = end_line_char(line_id, char_idx[4:0]);
                        bits = end_font_row(ch, char_row[2:0]);
                        end_text_line_pixel = bits[4 - char_col];
                    end
                end
            end
        end
    endfunction

