// =========================================================================
// METİN PİKSEL HESAPLAMA
// =========================================================================
logic [9:0] intro_line_y [0:11];
logic [9:0] intro_line_x [0:11];
logic [5:0] intro_line_len [0:11];
// Her satırın başlangıç koordinatları ve uzunlukları
assign intro_line_y[0]  = 10'd80;   assign intro_line_x[0]  = 10'd200; assign intro_line_len[0]  = 6'd20;
assign intro_line_y[1]  = 10'd110;  assign intro_line_x[1]  = 10'd160; assign intro_line_len[1]  = 6'd29;
assign intro_line_y[2]  = 10'd130;  assign intro_line_x[2]  = 10'd184; assign intro_line_len[2]  = 6'd23;
assign intro_line_y[3]  = 10'd150;  assign intro_line_x[3]  = 10'd180; assign intro_line_len[3]  = 6'd24;
assign intro_line_y[4]  = 10'd170;  assign intro_line_x[4]  = 10'd260; assign intro_line_len[4]  = 6'd11;
assign intro_line_y[5]  = 10'd210;  assign intro_line_x[5]  = 10'd172; assign intro_line_len[5]  = 6'd26;
assign intro_line_y[6]  = 10'd230;  assign intro_line_x[6]  = 10'd216; assign intro_line_len[6]  = 6'd17;
assign intro_line_y[7]  = 10'd270;  assign intro_line_x[7]  = 10'd176; assign intro_line_len[7]  = 6'd25;
assign intro_line_y[8]  = 10'd290;  assign intro_line_x[8]  = 10'd180; assign intro_line_len[8]  = 6'd24;
assign intro_line_y[9]  = 10'd310;  assign intro_line_x[9]  = 10'd196; assign intro_line_len[9]  = 6'd21;
assign intro_line_y[10] = 10'd330;  assign intro_line_x[10] = 10'd188; assign intro_line_len[10] = 6'd23;
assign intro_line_y[11] = 10'd350;  assign intro_line_x[11] = 10'd224; assign intro_line_len[11] = 6'd16;
// Continue yazısı koordinatları
localparam CONTINUE_X = 10'd430;
localparam CONTINUE_Y = 10'd440;
localparam CONTINUE_LEN = 6'd22;
// Intro metin pikseli hesaplama
always_comb begin
    intro_text_pixel = 1'b0;
    intro_continue_pixel = 1'b0;
    
    // Ana metin satırları
    for (int line = 0; line < 12; line++) begin
        if (v_count >= intro_line_y[line] && v_count < intro_line_y[line] + 10'd8) begin
            logic [9:0] rel_x;
            logic [3:0] char_row_idx;
            logic [5:0] char_idx;
            logic [2:0] pixel_in_char;
            logic [7:0] current_char;
            logic [7:0] char_bitmap;
            
            rel_x = h_count - intro_line_x[line];
            char_row_idx = v_count - intro_line_y[line];
            
            if (h_count >= intro_line_x[line] && rel_x < (intro_line_len[line] * 8)) begin
                char_idx = rel_x[8:3]; // rel_x / 8
                pixel_in_char = rel_x[2:0]; // rel_x % 8
                
                // Her satır için uygun karakteri seç
                case (line)
                    0:  current_char = (char_idx < 20) ? LINE1[char_idx] : 8'd32;
                    1:  current_char = (char_idx < 29) ? LINE2[char_idx] : 8'd32;
                    2:  current_char = (char_idx < 23) ? LINE3[char_idx] : 8'd32;
                    3:  current_char = (char_idx < 24) ? LINE4[char_idx] : 8'd32;
                    4:  current_char = (char_idx < 11) ? LINE5[char_idx] : 8'd32;
                    5:  current_char = (char_idx < 26) ? LINE6[char_idx] : 8'd32;
                    6:  current_char = (char_idx < 17) ? LINE7[char_idx] : 8'd32;
                    7:  current_char = (char_idx < 25) ? LINE8[char_idx] : 8'd32;
                    8:  current_char = (char_idx < 24) ? LINE9[char_idx] : 8'd32;
                    9:  current_char = (char_idx < 21) ? LINE10[char_idx] : 8'd32;
                    10: current_char = (char_idx < 23) ? LINE11[char_idx] : 8'd32;
                    11: current_char = (char_idx < 16) ? LINE12[char_idx] : 8'd32;
                    default: current_char = 8'd32;
                endcase
                
                char_bitmap = char_row(current_char, char_row_idx);
                if (char_bitmap[7 - pixel_in_char])
                    intro_text_pixel = 1'b1;
            end
        end
    end
    
    // Continue yazısı
    if (v_count >= CONTINUE_Y && v_count < CONTINUE_Y + 10'd8) begin
        logic [9:0] rel_x_cont;
        logic [3:0] char_row_idx_cont;
        logic [5:0] char_idx_cont;
        logic [2:0] pixel_in_char_cont;
        logic [7:0] current_char_cont;
        logic [7:0] char_bitmap_cont;
        
        rel_x_cont = h_count - CONTINUE_X;
        char_row_idx_cont = v_count - CONTINUE_Y;
        
        if (h_count >= CONTINUE_X && rel_x_cont < (CONTINUE_LEN * 8)) begin
            char_idx_cont = rel_x_cont[8:3];
            pixel_in_char_cont = rel_x_cont[2:0];
            
            current_char_cont = (char_idx_cont < 22) ? LINE_CONTINUE[char_idx_cont] : 8'd32;
            
            char_bitmap_cont = char_row(current_char_cont, char_row_idx_cont);
            if (char_bitmap_cont[7 - pixel_in_char_cont])
                intro_continue_pixel = 1'b1;
        end
    end
end


