always_comb begin
    rules_text_pixel  = 1'b0;
    rules_start_pixel = 1'b0;

    for (int rline = 0; rline < 11; rline++) begin
        logic [9:0] ry;
        logic [9:0] rx;
        logic [9:0] rel_x_rule;
        logic [3:0] char_row_rule;
        logic [6:0] char_idx_rule;
        logic [2:0] pixel_in_rule;
        logic [7:0] rule_char;
        logic [7:0] rule_bitmap;
        logic [6:0] rule_len;

        ry = 10'd42 + (rline * 10'd34);
        rx = (rline == 0) ? 10'd280 : 10'd20;

        if (v_count >= ry && v_count < ry + 10'd8 && h_count >= rx) begin
            case (rline)
                0: rule_len = 7'd10;
                1: rule_len = 7'd49;
                2: rule_len = 7'd44;
                3: rule_len = 7'd53;
                4: rule_len = 7'd50;
                5: rule_len = 7'd34;
                6: rule_len = 7'd45;
                7: rule_len = 7'd38;
                8: rule_len = 7'd41;
                9: rule_len = 7'd41;
                10: rule_len = 7'd45;
                default: rule_len = 7'd0;
            endcase

            rel_x_rule = h_count - rx;
            if (rel_x_rule < (rule_len * 10'd8)) begin
                char_row_rule = v_count - ry;
                char_idx_rule = rel_x_rule[9:3];
                pixel_in_rule = rel_x_rule[2:0];
                rule_char = get_rules_char(rline[3:0], char_idx_rule);
                rule_bitmap = char_row(rule_char, char_row_rule);
                if (rule_bitmap[7 - pixel_in_rule])
                    rules_text_pixel = 1'b1;
            end
        end
    end

    if (v_count >= 10'd440 && v_count < 10'd448 && h_count >= 10'd560 && h_count < 10'd600) begin
        logic [9:0] rel_x_start;
        logic [3:0] char_row_start;
        logic [2:0] char_idx_start;
        logic [2:0] pixel_in_start;
        logic [7:0] start_char;
        logic [7:0] start_bitmap;

        rel_x_start = h_count - 10'd560;
        char_row_start = v_count - 10'd440;
        char_idx_start = rel_x_start[5:3];
        pixel_in_start = rel_x_start[2:0];

        case (char_idx_start)
            3'd0: start_char = 8'd83;
            3'd1: start_char = 8'd84;
            3'd2: start_char = 8'd65;
            3'd3: start_char = 8'd82;
            3'd4: start_char = 8'd84;
            default: start_char = 8'd32;
        endcase

        start_bitmap = char_row(start_char, char_row_start);
        if (start_bitmap[7 - pixel_in_start])
            rules_start_pixel = 1'b1;
    end
end

