        case (vline)
            0: begin vy = 10'd35;  vx = 10'd236; vlen = 7'd21; end
            1: begin vy = 10'd170; vx = 10'd256; vlen = 7'd16; end
            2: begin vy = 10'd210; vx = 10'd208; vlen = 7'd28; end
            3: begin vy = 10'd245; vx = 10'd200; vlen = 7'd30; end
            4: begin vy = 10'd390; vx = 10'd164; vlen = 7'd39; end
            5: begin vy = 10'd408; vx = 10'd184; vlen = 7'd34; end
				6: begin vy = 10'd450; vx = 10'd224; vlen = 7'd24; end
            default: begin vy = 10'd0; vx = 10'd0; vlen = 7'd0; end
        endcase

        if (v_count >= vy && v_count < vy + 10'd8 && h_count >= vx) begin
            rel_x_vict = h_count - vx;
            if (rel_x_vict < (vlen * 10'd8)) begin
                char_row_vict = v_count - vy;
                char_idx_vict = rel_x_vict[9:3];
                pixel_in_vict = rel_x_vict[2:0];
                victory_char = get_victory_char(vline[2:0], char_idx_vict);
                victory_bitmap = char_row(victory_char, char_row_vict);
                if (victory_bitmap[7 - pixel_in_vict]) begin
                    if (vline == 0)
                        victory_title_pixel = 1'b1;
                    else if (vline <= 3)
                        victory_main_pixel = 1'b1;
                    else if (vline <= 5)
                        victory_prof_pixel = 1'b1;
						  else
                        victory_restart_pixel = 1'b1;	
                end
            end
        end
    end
end


