always_ff @(posedge clk_25M) begin
		 if (video_on && h_count < 10'd640 && v_count < 10'd480) begin
			  if (question_gate_idx == 5'd3)
				  formula_on <= FULL_SCREEN_BMP_Q3[v_count][639 - h_count];
			  else if (question_gate_idx == 5'd4)
				  formula_on <= FULL_SCREEN_BMP_Q4[v_count][639 - h_count];
			  else if (question_gate_idx == 5'd7)
				  formula_on <= FULL_SCREEN_BMP_Q7[v_count][639 - h_count];
			  else if (question_gate_idx == 5'd8)
				  formula_on <= FULL_SCREEN_BMP_Q8[v_count][639 - h_count];
			  else if (question_gate_idx == 5'd9)
				  formula_on <= FULL_SCREEN_BMP_Q9[v_count][639 - h_count];
			  else if (question_gate_idx == 5'd10)
				  formula_on <= FULL_SCREEN_BMP_Q10[v_count][639 - h_count];
			  else if (question_gate_idx == 5'd11)
				  formula_on <= FULL_SCREEN_BMP_Q11[v_count][639 - h_count];
			  else if (question_gate_idx == 5'd13)
				  formula_on <= FULL_SCREEN_BMP_Q13[v_count][639 - h_count];
			  else if (question_gate_idx == 5'd14)
				  formula_on <= FULL_SCREEN_BMP_Q14[v_count][639 - h_count];
			  else if (question_gate_idx == 5'd15)
				  formula_on <= FULL_SCREEN_BMP_Q15[v_count][639 - h_count];
			  else if (question_gate_idx == 5'd16)
				  formula_on <= FULL_SCREEN_BMP_Q11[v_count][639 - h_count];
			  else
				  formula_on <= FULL_SCREEN_BMP[v_count][639 - h_count];
		 end
		 else
			  formula_on <= 1'b0;
	 end
// =========================================================================
    // ODA KEŞİF SİSTEMİ (FOG OF WAR) - GÜVENLİ SENTEZ VERSIYONU
    // =========================================================================
    logic [14:0] visited_rooms; // 15 Odanın keşif durumu
    logic [3:0] player_room_idx;
    
    // Oyuncunun bulunduğu odanın 0-14 arası indeksi
    assign player_room_idx = room_row * 4'd5 + room_col;

    // Odaları ziyaret edildikçe hafızaya al
    always_ff @(posedge clk_25M or posedge real_reset) begin
        if (real_reset) begin
            // Sadece Sol Alt başlangıç odası açık (İndeks 10)
            visited_rooms <= 15'b0000_1000_0000_000; 
        end
        else begin
            // Güvenli Bitwise OR: Eski açık odalar korunur, yeni girilen oda (1) eklenir
            visited_rooms <= visited_rooms | (15'd1 << player_room_idx);
        end
    end

    // VGA Ekrana çizerken, o an çizilen pikselin hangi odaya ait olduğunu bul
    logic [2:0] pixel_room_col;
    logic [1:0] pixel_room_row;
    logic [3:0] pixel_room_idx;
    logic current_room_visible;
    logic expanded_current_room_visible;
    logic [9:0] player_center_x;
    logic [9:0] player_center_y;


    vga_pixel_room_indexer u_pixel_room_indexer (
        .px(h_count),
        .py(v_count),
        .pixel_room_col(pixel_room_col),
        .pixel_room_row(pixel_room_row),
        .pixel_room_idx(pixel_room_idx)
    );
    

    assign current_room_visible =
        visited_rooms[pixel_room_idx] || (pixel_room_idx == player_room_idx);

    assign player_center_x = square_x + (SQUARE_SIZE >> 1);
    assign player_center_y = square_y + (SQUARE_SIZE >> 1);

    assign expanded_current_room_visible =
        (h_count + 10'd100 >= player_center_x) &&
        (h_count <= player_center_x + 10'd100) &&
        (v_count + 10'd100 >= player_center_y) &&
        (v_count <= player_center_y + 10'd100);
// =========================================================================
	 
	 


    always_comb begin
        bmp_on = 1'b0;
        sx = 7'd0;
        sy = 7'd0;
        row_bits = 80'd0;

        if (h_count >= bmp_x && h_count < bmp_x + 10'd80 &&
            v_count >= bmp_y && v_count < bmp_y + 10'd80) begin
            sx = h_count - bmp_x;
            sy = v_count - bmp_y;
            row_bits = BMP[sy];
            bmp_on = ~row_bits[79 - sx];
        end
    end
    always_comb begin
        text_on = 1'b0;
        tx = 10'd0;
        ty = 10'd0;

        letter_p_on  = 1'b0;
        letter_r1_on = 1'b0;
        letter_o1_on = 1'b0;
        letter_f1_on = 1'b0;
        letter_e2_on = 1'b0;
        letter_s1_on = 1'b0;
        letter_s2_on = 1'b0;
        letter_o2_on = 1'b0;
        letter_r2_on = 1'b0;

        if (h_count >= text_x && h_count < text_x + 10'd94 &&
            v_count >= text_y && v_count < text_y + 10'd14) begin
            tx = h_count - text_x;
            ty = v_count - text_y;

            if ((tx >= 10'd0 && tx < 10'd2 && ty < 10'd14) ||
                (tx >= 10'd0 && tx < 10'd8 && ty < 10'd2) ||
                (tx >= 10'd6 && tx < 10'd8 && ty < 10'd8) ||
                (tx >= 10'd0 && tx < 10'd8 && ty >= 10'd6 && ty < 10'd8))
                letter_p_on = 1'b1;

            if ((tx >= 10'd10 && tx < 10'd12 && ty < 10'd14) ||
                (tx >= 10'd10 && tx < 10'd18 && ty < 10'd2) ||
                (tx >= 10'd16 && tx < 10'd18 && ty < 10'd8) ||
                (tx >= 10'd10 && tx < 10'd18 && ty >= 10'd6 && ty < 10'd8) ||
                (tx >= 10'd14 && tx < 10'd16 && ty >= 10'd8 && ty < 10'd14) ||
                (tx >= 10'd16 && tx < 10'd18 && ty >= 10'd10 && ty < 10'd14))
                letter_r1_on = 1'b1;

            if ((tx >= 10'd20 && tx < 10'd22 && ty >= 10'd2 && ty < 10'd12) ||
                (tx >= 10'd28 && tx < 10'd30 && ty >= 10'd2 && ty < 10'd12) ||
                (tx >= 10'd22 && tx < 10'd28 && ty < 10'd2) ||
                (tx >= 10'd22 && tx < 10'd28 && ty >= 10'd12 && ty < 10'd14))
                letter_o1_on = 1'b1;

            if ((tx >= 10'd34 && tx < 10'd36 && ty < 10'd14) ||
                (tx >= 10'd34 && tx < 10'd42 && ty < 10'd2) ||
                (tx >= 10'd34 && tx < 10'd41 && ty >= 10'd6 && ty < 10'd8))
                letter_f1_on = 1'b1;

            if ((tx >= 10'd44 && tx < 10'd46 && ty < 10'd14) ||
                (tx >= 10'd44 && tx < 10'd52 && ty < 10'd2) ||
                (tx >= 10'd44 && tx < 10'd51 && ty >= 10'd6 && ty < 10'd8) ||
                (tx >= 10'd44 && tx < 10'd52 && ty >= 10'd12 && ty < 10'd14))
                letter_e2_on = 1'b1;

            if ((tx >= 10'd54 && tx < 10'd62 && ty < 10'd2) ||
                (tx >= 10'd54 && tx < 10'd56 && ty >= 10'd2 && ty < 10'd8) ||
                (tx >= 10'd54 && tx < 10'd62 && ty >= 10'd6 && ty < 10'd8) ||
                (tx >= 10'd60 && tx < 10'd62 && ty >= 10'd8 && ty < 10'd12) ||
                (tx >= 10'd54 && tx < 10'd62 && ty >= 10'd12 && ty < 10'd14))
                letter_s1_on = 1'b1;

            if ((tx >= 10'd64 && tx < 10'd72 && ty < 10'd2) ||
                (tx >= 10'd64 && tx < 10'd66 && ty >= 10'd2 && ty < 10'd8) ||
                (tx >= 10'd64 && tx < 10'd72 && ty >= 10'd6 && ty < 10'd8) ||
                (tx >= 10'd70 && tx < 10'd72 && ty >= 10'd8 && ty < 10'd12) ||
                (tx >= 10'd64 && tx < 10'd72 && ty >= 10'd12 && ty < 10'd14))
                letter_s2_on = 1'b1;

            if ((tx >= 10'd74 && tx < 10'd76 && ty >= 10'd2 && ty < 10'd12) ||
                (tx >= 10'd82 && tx < 10'd84 && ty >= 10'd2 && ty < 10'd12) ||
                (tx >= 10'd76 && tx < 10'd82 && ty < 10'd2) ||
                (tx >= 10'd76 && tx < 10'd82 && ty >= 10'd12 && ty < 10'd14))
                letter_o2_on = 1'b1;

            if ((tx >= 10'd86 && tx < 10'd88 && ty < 10'd14) ||
                (tx >= 10'd86 && tx < 10'd94 && ty < 10'd2) ||
                (tx >= 10'd92 && tx < 10'd94 && ty < 10'd8) ||
                (tx >= 10'd86 && tx < 10'd94 && ty >= 10'd6 && ty < 10'd8) ||
                (tx >= 10'd90 && tx < 10'd92 && ty >= 10'd8 && ty < 10'd14) ||
                (tx >= 10'd92 && tx < 10'd94 && ty >= 10'd10 && ty < 10'd14))
                letter_r2_on = 1'b1;

            if (letter_p_on || letter_r1_on || letter_o1_on ||
                letter_f1_on || letter_e2_on || letter_s1_on ||
                letter_s2_on || letter_o2_on || letter_r2_on)
                text_on = 1'b1;
        end
    end

    always_comb begin
        if (square_x <= 10'd128)
            room_col = 3'd0;
        else if (square_x <= 10'd256)
            room_col = 3'd1;
        else if (square_x <= 10'd384)
            room_col = 3'd2;
        else if (square_x <= 10'd512)
            room_col = 3'd3;
        else
            room_col = 3'd4;
    end

    always_comb begin
        if (square_y <= 10'd160)
            room_row = 2'd0;
        else if (square_y <= 10'd320)
            room_row = 2'd1;
        else
            room_row = 2'd2;
    end

    always_comb begin
        room_id = room_row * 4'd5 + room_col + 4'd1;
    end

    always_comb begin
        case (room_col)
            3'd0: begin
                room_left_inner  = 10'd0;
                room_right_inner = 10'd126;
            end
            3'd1: begin
                room_left_inner  = 10'd129;
                room_right_inner = 10'd254;
            end
            3'd2: begin
                room_left_inner  = 10'd257;
                room_right_inner = 10'd382;
            end
            3'd3: begin
                room_left_inner  = 10'd385;
                room_right_inner = 10'd510;
            end
            default: begin
                room_left_inner  = 10'd513;
                room_right_inner = 10'd639;
            end
        endcase

        case (room_row)
            2'd0: begin
                room_top_inner    = 10'd0;
                room_bottom_inner = 10'd158;
            end
            2'd1: begin
                room_top_inner    = 10'd161;
                room_bottom_inner = 10'd318;
            end
            default: begin
                room_top_inner    = 10'd321;
                room_bottom_inner = 10'd479;
            end
        endcase
    end

			 
			 always_comb begin
				 next_x = square_x;
				 next_y = square_y;

				 // Visited gate'lerin açtığı geçit koşulları
				 // Karakter gate bounding box'ının içindeyken o yönde oda duvarı kontrolü bypass edilir


gate_pass_h =
					  (gate_visited[4]  && square_x + SQUARE_SIZE > 10'd490 && square_x < 10'd540 && square_y + SQUARE_SIZE > 10'd85  && square_y < 10'd115) ||
					  (gate_visited[6]  && square_x + SQUARE_SIZE > 10'd364 && square_x < 10'd404 && square_y + SQUARE_SIZE > 10'd390 && square_y < 10'd410) ||
					  (gate_visited[9]  && square_x + SQUARE_SIZE > 10'd372 && square_x < 10'd388 && square_y + SQUARE_SIZE > 10'd220 && square_y < 10'd260) ||
					  (gate_visited[10] && square_x + SQUARE_SIZE > 10'd100 && square_x < 10'd160 && square_y + SQUARE_SIZE > 10'd220 && square_y < 10'd260) ||
					  (gate_visited[11] && square_x + SQUARE_SIZE > 10'd100 && square_x < 10'd155 && square_y + SQUARE_SIZE > 10'd10  && square_y < 10'd150) ||
					  (gate_visited[15] && square_x + SQUARE_SIZE > 10'd100 && square_x < 10'd160 && square_y + SQUARE_SIZE > 10'd320 && square_y < 10'd480) ||
					  (gate_visited[14] && square_x + SQUARE_SIZE > 10'd360 && square_x < 10'd415 && square_y + SQUARE_SIZE > 10'd85  && square_y < 10'd115) ||
					  // 512. sütunda 320-345 arası açtığımız yeni geçit:
					  (square_x > 10'd490 && square_x < 10'd520 && square_y >= 10'd320 && square_y <= 10'd335);

				 gate_pass_v =
					  (gate_visited[0]  && square_x + SQUARE_SIZE > 10'd170 && square_x < 10'd210 && square_y + SQUARE_SIZE > 10'd122 && square_y < 10'd182) ||
					  //(gate_visited[1]  && square_x + SQUARE_SIZE > 10'd426 && square_x < 10'd466 && square_y + SQUARE_SIZE > 10'd122 && square_y < 10'd182) ||
					  (gate_visited[2]  && square_x + SQUARE_SIZE > 10'd40  && square_x < 10'd90  && square_y + SQUARE_SIZE > 10'd120 && square_y < 10'd190) ||
					  (gate_visited[3]  && square_x + SQUARE_SIZE > 10'd310 && square_x < 10'd330 && square_y + SQUARE_SIZE > 10'd140 && square_y < 10'd180) ||
					  (gate_visited[7]  && square_x + SQUARE_SIZE > 10'd561 && square_x < 10'd591 && square_y + SQUARE_SIZE > 10'd295 && square_y < 10'd350) ||
					  ((gate_visited[8] || gate8_opened) && square_x + SQUARE_SIZE > 10'd0 && square_x < 10'd128 && square_y + SQUARE_SIZE > 10'd290 && square_y < 10'd350) ||
					  (gate_visited[12] && square_x + SQUARE_SIZE > 10'd305 && square_x < 10'd335 && square_y + SQUARE_SIZE > 10'd295 && square_y < 10'd350) ||
					  (gate_visited[13] && square_x + SQUARE_SIZE > 10'd128 && square_x < 10'd256 && square_y + SQUARE_SIZE > 10'd295 && square_y < 10'd350) ||
				  (gate_visited[16] && square_x + SQUARE_SIZE > 10'd232 && square_x < 10'd280 && square_y + SQUARE_SIZE > 10'd40  && square_y < 10'd120);
					  
					  

				 if (btn_right) begin
					  if (square_x + SQUARE_SIZE + STEP < 10'd640) begin
							if (((square_x + STEP + SQUARE_SIZE - 10'd1) <= room_right_inner || gate_pass_h ||
								 (room_row == 2'd1 && room_col == 3'd1) ||
								 (room_row == 2'd2 && room_col == 3'd3 && passage_14_15_open)) && !extra_wall_block_right)
								 next_x = square_x + STEP;
					  end
				 end
				 else if (btn_left) begin
					  if (square_x >= STEP) begin
							if (((square_x - STEP) >= room_left_inner || gate_pass_h ||
								 (room_row == 2'd1 && room_col == 3'd2) ||
								 (room_row == 2'd2 && room_col == 3'd4 && passage_14_15_open)) && !extra_wall_block_left)
								 next_x = square_x - STEP;
					  end
				 end

				 if (btn_down) begin
					  if (square_y + SQUARE_SIZE + STEP < 10'd480) begin
							if (((square_y + STEP + SQUARE_SIZE - 10'd1) <= room_bottom_inner || gate_pass_v ||
								 (room_row == 2'd0 && room_col == 3'd4) ||
								 (room_row == 2'd1 && room_col == 3'd3)) && !extra_wall_block_down)
								 next_y = square_y + STEP;
					  end
				 end
				 else if (btn_up) begin
					  if (square_y >= STEP) begin
							if (((square_y - STEP) >= room_top_inner || gate_pass_v ||
								 (room_row == 2'd1 && room_col == 3'd4) ||
								 (room_row == 2'd2 && room_col == 3'd3)) && !extra_wall_block_up)
								 next_y = square_y - STEP;
					  end
				 end
			end

    
// =========================================================================
// OPTİMİZE EDİLMİŞ NAND GATE (X=512, Y=100)
// =========================================================================
logic nand_gate_on; // Sadece burada tanımlı kalsın
always_comb begin
    // Dahili logic tanımları
    logic n_rect, n_semi, n_bub, n_i1, n_i2, n_out;
    logic signed [11:0] dx_n, dy_n, dx_nb, dy_nb;
    logic [23:0] d2_n, d2_nb;

    // Resetler
    n_rect = 0; n_semi = 0; n_bub = 0; n_i1 = 0; n_i2 = 0; n_out = 0; nand_gate_on = 0;
    dx_n = 0; dy_n = 0; d2_n = 0; dx_nb = 0; dy_nb = 0; d2_nb = 0;

    // Sadece bu bölgedeyken hesaplama yap (No Signal hatasını çözen kısım)
    if (h_count >= 10'd490 && h_count <= 10'd540 && v_count >= 10'd85 && v_count <= 10'd115) begin
        
        if (h_count >= 10'd502 && h_count <= 10'd512 && v_count >= 10'd90 && v_count <= 10'd110)
            n_rect = 1'b1;
        
        dx_n = $signed({1'b0, h_count}) - 12'sd512;
        dy_n = $signed({1'b0, v_count}) - 12'sd100;
        d2_n = dx_n * dx_n + dy_n * dy_n;
        
        if (d2_n <= 24'd100 && h_count >= 10'd512) n_semi = 1'b1;
        
        dx_nb = $signed({1'b0, h_count}) - 12'sd525;
        dy_nb = $signed({1'b0, v_count}) - 12'sd100;
        d2_nb = dx_nb * dx_nb + dy_nb * dy_nb;
        
        if (d2_nb <= 24'd16) n_bub = 1'b1;
        
        if (h_count >= 10'd492 && h_count <= 10'd502 && v_count >= 10'd94 && v_count <= 10'd96) n_i1 = 1'b1;
        if (h_count >= 10'd492 && h_count <= 10'd502 && v_count >= 10'd104 && v_count <= 10'd106) n_i2 = 1'b1;
        if (h_count >= 10'd525 && h_count <= 10'd535 && v_count >= 10'd99 && v_count <= 10'd101) n_out = 1'b1;
            
        nand_gate_on = (n_rect || n_semi || n_bub || n_i1 || n_i2 || n_out);
    end
end

    
    
// =========================================================================
    // SARI ÇİZGİLERİN ÜZERİNE EKLENEN 4 YENİ OR KAPISI
    // =========================================================================

    logic line_or4_on;

// =========================================================================
// OPTİMİZE EDİLMİŞ XNOR GATE (X=384, Y=100) [SAĞA BAKAN]
// =========================================================================
logic new_xnor_384_on; 

always_comb begin
    // Değişkenleri kendi içinde tanımlıyoruz ki çakışma olmasın
    logic xnr_main, xnr_body, xnr_back, xnr_bub, xnr_i1, xnr_i2, xnr_out;
    logic signed [11:0] dx_m, dy_m, dx_c, dy_c, dx_b, dy_b, dx_bub, dy_bub;
    logic [23:0] d2_m, d2_c, d2_b, d2_bub;

    // Resetler (Zorunlu)
    xnr_main = 0; xnr_body = 0; xnr_back = 0; xnr_bub = 0;
    xnr_i1 = 0; xnr_i2 = 0; xnr_out = 0; new_xnor_384_on = 0;
    dx_m=0; dy_m=0; d2_m=0; dx_c=0; dy_c=0; d2_c=0; dx_b=0; dy_b=0; d2_b=0; dx_bub=0; dy_bub=0; d2_bub=0;

    // BOUNDING BOX: FPGA'in hesaplama yükünü sadece bu kareyle sınırlandırıyoruz (No Signal Koruması)
    if (h_count >= 10'd360 && h_count <= 10'd415 && v_count >= 10'd85 && v_count <= 10'd115) begin
        
        // 1. Ana Kavis (Main Curve)
        dx_m = $signed({1'b0, h_count}) - 12'sd384; 
        dy_m = $signed({1'b0, v_count}) - 12'sd100;
        d2_m = dx_m*dx_m + dy_m*dy_m;
        if (d2_m <= 24'd100 && h_count >= 10'd384) xnr_main = 1'b1;

        // 2. İç Boşluk / Gövde (Body)
        dx_c = $signed({1'b0, h_count}) - 12'sd374; 
        dy_c = $signed({1'b0, v_count}) - 12'sd100;
        d2_c = dx_c*dx_c + dy_c*dy_c;
        if (h_count >= 10'd374 && h_count <= 10'd384 && v_count >= 10'd90 && v_count <= 10'd110 && d2_c > 24'd100) 
            xnr_body = 1'b1;

        // 3. XNOR'a özel ayrık arka kavis (Back Curve)
        dx_b = $signed({1'b0, h_count}) - 12'sd373; 
        dy_b = $signed({1'b0, v_count}) - 12'sd100;
        d2_b = dx_b*dx_b + dy_b*dy_b;
        if (d2_b >= 24'd49 && d2_b <= 24'd64 && h_count >= 10'd373) 
            xnr_back = 1'b1;

        // 4. XNOR Yuvarlağı (Bubble)
        dx_bub = $signed({1'b0, h_count}) - 12'sd397; 
        dy_bub = $signed({1'b0, v_count}) - 12'sd100;
        d2_bub = dx_bub*dx_bub + dy_bub*dy_bub;
        if (d2_bub <= 24'd16) 
            xnr_bub = 1'b1;

        // 5. Giriş ve Çıkış Pinleri
        if (h_count >= 10'd362 && h_count <= 10'd372 && v_count >= 10'd94 && v_count <= 10'd96) xnr_i1 = 1'b1;
        if (h_count >= 10'd362 && h_count <= 10'd372 && v_count >= 10'd104 && v_count <= 10'd106) xnr_i2 = 1'b1;
        if (h_count >= 10'd401 && h_count <= 10'd411 && v_count >= 10'd99 && v_count <= 10'd101) xnr_out = 1'b1;

        // Boyama sinyalini aktif et
        new_xnor_384_on = (xnr_main || xnr_body || xnr_back || xnr_bub || xnr_i1 || xnr_i2 || xnr_out);
    end
end

    

    // --- OR 4 (X=260, Y=100) ---
    logic lor4_s1, lor4_s2, lor4_bet, lor4_in1, lor4_in2, lor4_out;
    logic signed [11:0] dx_lor4, dy_lor4, dx_lor4_2, dy_lor4_2;
    logic [23:0] dist2_lor4, dist2_lor4_2;

    always_comb begin
        lor4_s1=0; lor4_s2=0; lor4_bet=0; lor4_in1=0; lor4_in2=0; lor4_out=0; line_or4_on=0;
        
        dx_lor4_2 = $signed({1'b0, h_count}) - 12'sd250; dy_lor4_2 = $signed({1'b0, v_count}) - 12'sd100;
        dist2_lor4_2 = dx_lor4_2 * dx_lor4_2 + dy_lor4_2 * dy_lor4_2;
        if (dist2_lor4_2 <= 24'd100 && h_count >= 10'd250) lor4_s2 = 1'b1;

        dx_lor4 = $signed({1'b0, h_count}) - 12'sd260; dy_lor4 = $signed({1'b0, v_count}) - 12'sd100;
        dist2_lor4 = dx_lor4 * dx_lor4 + dy_lor4 * dy_lor4;
        if (dist2_lor4 <= 24'd100 && h_count >= 10'd260) lor4_s1 = 1'b1;

        if (h_count >= 10'd250 && h_count <= 10'd260 && v_count >= 10'd90 && v_count <= 10'd110 && !(lor4_s2 || lor4_s1)) lor4_bet = 1'b1;
        if (h_count >= 10'd245 && h_count <= 10'd255 && v_count >= 10'd94 && v_count <= 10'd96) lor4_in1 = 1'b1;
        if (h_count >= 10'd245 && h_count <= 10'd255 && v_count >= 10'd104 && v_count <= 10'd106) lor4_in2 = 1'b1;
        if (h_count >= 10'd270 && h_count <= 10'd280 && v_count >= 10'd99 && v_count <= 10'd101) lor4_out = 1'b1;
        if (lor4_s1 || lor4_bet || lor4_in1 || lor4_in2 || lor4_out) line_or4_on = 1'b1;
    end
    
// =========================================================================
    // AŞAĞI BAKAN OR KAPISI (X=190, Y=152 - 8 birim daha yukarı kaydırıldı)
    // =========================================================================
    logic down_or2_on;

    always_comb begin
        // Değişkenleri içeride tanımlıyoruz ki çakışma olmasın
        logic dor_bot_curve, dor_cutout, dor_body;
        logic dor_in1, dor_in2, dor_out;
        logic signed [11:0] dx_dor_bot, dy_dor_bot, dx_dor_cut, dy_dor_cut;
        logic [23:0] dist2_dor_bot, dist2_dor_cut;

        // Başlangıç değerleri (Latch önlemek ve No Signal hatasından kaçınmak için)
        dor_bot_curve = 0; dor_cutout = 0; dor_body = 0;
        dor_in1 = 0; dor_in2 = 0; dor_out = 0; down_or2_on = 0;
        dx_dor_bot=0; dy_dor_bot=0; dist2_dor_bot=0;
        dx_dor_cut=0; dy_dor_cut=0; dist2_dor_cut=0;

        // BOUNDING BOX (Sadece bu alan içindeyken hesapla)
        if (h_count >= 10'd170 && h_count <= 10'd210 && v_count >= 10'd122 && v_count <= 10'd182) begin
            
            // 1. Kesik Kısım (Cutout) - Kapının ÜSTÜNDEKİ kavisli boşluk (Merkez Y: 147)
            dx_dor_cut = $signed({1'b0, h_count}) - 12'sd190;
            dy_dor_cut = $signed({1'b0, v_count}) - 12'sd147;
            dist2_dor_cut = dx_dor_cut * dx_dor_cut + dy_dor_cut * dy_dor_cut;
            
            // Alt yarısını (v_count >= 147) gövdeden oyarak çıkaracağız
            if (dist2_dor_cut <= 24'd100 && v_count >= 10'd147)
                dor_cutout = 1'b1;

            // 2. Alt Yuvarlak Kısım (Bottom curve) - (Merkez Y: 157)
            dx_dor_bot = $signed({1'b0, h_count}) - 12'sd190;
            dy_dor_bot = $signed({1'b0, v_count}) - 12'sd157;
            dist2_dor_bot = dx_dor_bot * dx_dor_bot + dy_dor_bot * dy_dor_bot;
            
            // Sadece alt yarısını (v_count >= 157) çizeceğiz
            if (dist2_dor_bot <= 24'd100 && v_count >= 10'd157)
                dor_bot_curve = 1'b1;

            // 3. Orta Gövde (Body) - Y: 147..157 arası
            // Cutout'u gövdeden çıkarıyoruz (!dor_cutout)
            if (h_count >= 10'd180 && h_count <= 10'd200 && v_count >= 10'd147 && v_count <= 10'd157 && !dor_cutout)
                dor_body = 1'b1;

            // 4. Giriş Bacakları (Inputs) - Yukarıdan gelir (Y: 134..150)
            if (h_count >= 10'd184 && h_count <= 10'd186 && v_count >= 10'd134 && v_count <= 10'd150) dor_in1 = 1'b1;
            if (h_count >= 10'd194 && h_count <= 10'd196 && v_count >= 10'd134 && v_count <= 10'd150) dor_in2 = 1'b1;

            // 5. Çıkış Bacağı (Output) - Aşağıdan çıkar (Y: 167..177)
            if (h_count >= 10'd189 && h_count <= 10'd191 && v_count >= 10'd167 && v_count <= 10'd177) dor_out = 1'b1;

            // Hepsini birleştirip boyama sinyalini aktif et
            down_or2_on = (dor_bot_curve || dor_body || dor_in1 || dor_in2 || dor_out);
        end
    end
	     
    
     // =========================================================================
    // YENİ EKLENEN 6 ADET AND KAPISI
    // =========================================================================

    logic new_and_1_on, new_and_2_on, new_and_3_on, new_and_4_on, new_and_6_on;

// =========================================================================
    // YENİ YUKARI BAKAN NOR KAPISI (X=64, Y=160)
    // =========================================================================
    logic up_nor_64_on;
    always_comb begin
        // Değişkenleri içeride tanımlıyoruz ki karışmasın
        logic un_top, un_cut, un_body, un_bub, un_i1, un_i2, un_out;
        logic signed [11:0] dx_t, dy_t, dx_c, dy_c, dx_b, dy_b;
        logic [23:0] d2_t, d2_c, d2_b;
        
        // Resetler (Zorunlu)
        un_top=0; un_cut=0; un_body=0; un_bub=0; un_i1=0; un_i2=0; un_out=0; up_nor_64_on=0;
        dx_t=0; dy_t=0; d2_t=0; dx_c=0; dy_c=0; d2_c=0; dx_b=0; dy_b=0; d2_b=0;

        // BOUNDING BOX: FPGA'i yormamak için sadece bu koordinatlardayken hesapla
        if (h_count >= 10'd40 && h_count <= 10'd90 && v_count >= 10'd120 && v_count <= 10'd190) begin
            
            // 1. Üst Kavis (Top Curve) - Merkez: (64, 160)
            dx_t = $signed({1'b0, h_count}) - 12'sd64;
            dy_t = $signed({1'b0, v_count}) - 12'sd160;
            d2_t = dx_t*dx_t + dy_t*dy_t;
            if (d2_t <= 24'd100 && v_count <= 10'd160) un_top = 1'b1;

            // 2. Alt Boşluk Kavis (Cutout) - Merkez: (64, 170)
            dx_c = $signed({1'b0, h_count}) - 12'sd64;
            dy_c = $signed({1'b0, v_count}) - 12'sd170;
            d2_c = dx_c*dx_c + dy_c*dy_c;

            // 3. Gövde (Body) - İç kavis dışındaysa
            if (h_count >= 10'd54 && h_count <= 10'd74 && v_count >= 10'd160 && v_count <= 10'd170 && d2_c > 24'd100)
                un_body = 1'b1;

            // 4. NOR Yuvarlağı (Bubble) - Merkez: (64, 146)
            dx_b = $signed({1'b0, h_count}) - 12'sd64;
            dy_b = $signed({1'b0, v_count}) - 12'sd146;
            d2_b = dx_b*dx_b + dy_b*dy_b;
            if (d2_b <= 24'd16) un_bub = 1'b1;

            // 5. Girişler (Inputs) - Alttan gelir
            if (h_count >= 10'd58 && h_count <= 10'd60 && v_count >= 10'd166 && v_count <= 10'd176) un_i1 = 1'b1;
            if (h_count >= 10'd68 && h_count <= 10'd70 && v_count >= 10'd166 && v_count <= 10'd176) un_i2 = 1'b1;

            // 6. Çıkış (Output) - Yuvarlağın üstünden çıkar
            if (h_count >= 10'd63 && h_count <= 10'd65 && v_count >= 10'd136 && v_count <= 10'd142) un_out = 1'b1;

            // Hepsini birleştirip boyama sinyalini tetikle
            up_nor_64_on = (un_top || un_body || un_bub || un_i1 || un_i2 || un_out);
        end
    end

    // --- 2. AND Kapısı: Orta Üst Yatay Çizgi (X=320, Y=160) [YUKARI BAKAN] ---
    logic a2_rect, a2_semi, a2_in1, a2_in2, a2_out;
    logic signed [11:0] dx_a2, dy_a2; logic [23:0] dist2_a2;
    always_comb begin
        a2_rect=0; a2_semi=0; a2_in1=0; a2_in2=0; a2_out=0; new_and_2_on=0;
        if (h_count >= 10'd310 && h_count <= 10'd330 && v_count >= 10'd160 && v_count <= 10'd170) a2_rect = 1'b1;
        dx_a2 = $signed({1'b0, h_count}) - 12'sd320; dy_a2 = $signed({1'b0, v_count}) - 12'sd160;
