        if (h_count >= 10'd324 && h_count <= 10'd326 && v_count >= 10'd170 && v_count <= 10'd180) a2_in2 = 1'b1;
        if (h_count >= 10'd319 && h_count <= 10'd321 && v_count >= 10'd140 && v_count <= 10'd150) a2_out = 1'b1;
        if (a2_rect || a2_semi || a2_in1 || a2_in2 || a2_out) new_and_2_on = 1'b1;
