        if (h_count >= 10'd580 && h_count <= 10'd582 && v_count >= 10'd330 && v_count <= 10'd340) a6_in2 = 1'b1;
        if (h_count >= 10'd575 && h_count <= 10'd577 && v_count >= 10'd300 && v_count <= 10'd310) a6_out = 1'b1;
        if (a6_rect || a6_semi || a6_in1 || a6_in2 || a6_out) new_and_6_on = 1'b1;
