        uo_top=0; uo_cut=0; uo_body=0; uo_i1=0; uo_i2=0; uo_out=0; up_or_64_on=0;
        dx_t=0; dy_t=0; d2_t=0; dx_c=0; dy_c=0; d2_c=0;

        // BOUNDING BOX: FPGA yorulmasın diye sadece bu alandayken hesaplama yapıyoruz
        if (h_count >= 10'd40 && h_count <= 10'd90 && v_count >= 10'd290 && v_count <= 10'd350) begin
            
            // 1. Üst Kavis (Top Curve) - Merkez: (64, 320)
            dx_t = $signed({1'b0, h_count}) - 12'sd64;
