            d2_t = dx_t*dx_t + dy_t*dy_t;
            if (d2_t <= 24'd100 && v_count <= 10'd320) uo_top = 1'b1;

            // 2. Alt Boşluk Kavis (Cutout) - Merkez: (64, 330)
            dx_c = $signed({1'b0, h_count}) - 12'sd64;
