            if (h_count >= 10'd54 && h_count <= 10'd74 && v_count >= 10'd320 && v_count <= 10'd330 && !uo_cut)
                uo_body = 1'b1;

            // 4. Giriş Bacakları (Inputs) - Alttan gelir
            if (h_count >= 10'd58 && h_count <= 10'd60 && v_count >= 10'd326 && v_count <= 10'd336) uo_i1 = 1'b1;
