    logic new_nor1_on;
    logic nn1_semi, nn1_semi2, nn1_between, nn1_bubble;
    logic nn1_in1, nn1_in2, nn1_out;

    logic signed [11:0] dx_nn1, dy_nn1; logic [23:0] dist2_nn1;
    logic signed [11:0] dx_nn1_2, dy_nn1_2; logic [23:0] dist2_nn1_2;
    logic signed [11:0] dx_nn1_b, dy_nn1_b; logic [23:0] dist2_nn1_b;

    always_comb begin
        nn1_semi=0; nn1_semi2=0; nn1_between=0; nn1_bubble=0;
        nn1_in1=0; nn1_in2=0; nn1_out=0; new_nor1_on=0;

        // 1. Sağ kavis (Top curve) - Merkez: X=384, Y=240
        dx_nn1 = $signed({1'b0, h_count}) - 12'sd384;
        dy_nn1 = $signed({1'b0, v_count}) - 12'sd240;
        dist2_nn1 = dx_nn1 * dx_nn1 + dy_nn1 * dy_nn1;
        if (dist2_nn1 <= 24'd100 && h_count >= 10'd384)
