        // 2. Sol kavis boşluğu (Cutout) - Merkez: X=374, Y=240
        dx_nn1_2 = $signed({1'b0, h_count}) - 12'sd374;
        dy_nn1_2 = $signed({1'b0, v_count}) - 12'sd240;
        dist2_nn1_2 = dx_nn1_2 * dx_nn1_2 + dy_nn1_2 * dy_nn1_2;
        if (dist2_nn1_2 <= 24'd100 && h_count >= 10'd374)
            nn1_semi2 = 1'b1;

        // 3. Gövde (Body) - Kavislerin arası
        if (h_count >= 10'd374 && h_count <= 10'd384 && v_count >= 10'd230 && v_count <= 10'd250 && !(nn1_semi || nn1_semi2))
            nn1_between = 1'b1;

        // 4. NOR Yuvarlağı (Bubble) - Kapının ucunda (Merkez: X=397, Y=240)
        dx_nn1_b = $signed({1'b0, h_count}) - 12'sd397;
        dy_nn1_b = $signed({1'b0, v_count}) - 12'sd240;
        dist2_nn1_b = dx_nn1_b * dx_nn1_b + dy_nn1_b * dy_nn1_b;
        if (dist2_nn1_b <= 24'd16)
            nn1_bubble = 1'b1;

        // 5. Giriş ve Çıkış Bacakları
        if (h_count >= 10'd369 && h_count <= 10'd379 && v_count >= 10'd234 && v_count <= 10'd236) nn1_in1 = 1'b1; // Üst giriş
        if (h_count >= 10'd369 && h_count <= 10'd379 && v_count >= 10'd244 && v_count <= 10'd246) nn1_in2 = 1'b1; // Alt giriş
        if (h_count >= 10'd397 && h_count <= 10'd407 && v_count >= 10'd239 && v_count <= 10'd241) nn1_out = 1'b1; // Çıkış bacağı

        // Hepsini birleştirip boyama sinyalini aktif et
        if (nn1_semi || nn1_between || nn1_bubble || nn1_in1 || nn1_in2 || nn1_out)
            new_nor1_on = 1'b1;
    end
	 
	 // =========================================================================
    // YENİ NAND KAPISI (X=128, Y=400) [SAĞA BAKAN]
