        logic nnd_rect, nnd_semi, nnd_bub, nnd_i1, nnd_i2, nnd_out;
        logic signed [11:0] dx_semi, dy_semi, dx_bub, dy_bub;
        logic [23:0] d2_semi, d2_bub;

        // Resetler (Zorunlu)
        nnd_rect=0; nnd_semi=0; nnd_bub=0; nnd_i1=0; nnd_i2=0; nnd_out=0; new_nand_128_400_on=0;
        dx_semi=0; dy_semi=0; d2_semi=0; dx_bub=0; dy_bub=0; d2_bub=0;

