        if (h_count >= 10'd100 && h_count <= 10'd160 && v_count >= 10'd380 && v_count <= 10'd420) begin
            
            // 1. Gövde (Dikdörtgen) - X: 118..128, Y: 390..410
            if (h_count >= 10'd118 && h_count <= 10'd128 && v_count >= 10'd390 && v_count <= 10'd410)
                nnd_rect = 1'b1;

            // 2. Yarım Daire (Semi-circle) - Merkez: (128, 400)
            dx_semi = $signed({1'b0, h_count}) - 12'sd128;
            dy_semi = $signed({1'b0, v_count}) - 12'sd400;
            d2_semi = dx_semi*dx_semi + dy_semi*dy_semi;
            if (d2_semi <= 24'd100 && h_count >= 10'd128) 
                nnd_semi = 1'b1;

            // 3. NAND Yuvarlağı (Bubble) - Merkez: (141, 400)
            dx_bub = $signed({1'b0, h_count}) - 12'sd141;
            dy_bub = $signed({1'b0, v_count}) - 12'sd400;
            d2_bub = dx_bub*dx_bub + dy_bub*dy_bub;
            if (d2_bub <= 24'd16) 
                nnd_bub = 1'b1;

            // 4. Giriş Bacakları (Inputs) - Soldan gelir
            if (h_count >= 10'd106 && h_count <= 10'd118 && v_count >= 10'd394 && v_count <= 10'd396) nnd_i1 = 1'b1;
            if (h_count >= 10'd106 && h_count <= 10'd118 && v_count >= 10'd404 && v_count <= 10'd406) nnd_i2 = 1'b1;

            // 5. Çıkış Bacağı (Output) - Sağdan çıkar
            if (h_count >= 10'd145 && h_count <= 10'd155 && v_count >= 10'd399 && v_count <= 10'd401) nnd_out = 1'b1;

            // Birleştirme (Sinyali ekrana gönder)
            new_nand_128_400_on = (nnd_rect || nnd_semi || nnd_bub || nnd_i1 || nnd_i2 || nnd_out);
        end
    end
    
// =========================================================================
    // YENİ XNOR KAPISI (X=128, Y=240) [SAĞA BAKAN]
    // =========================================================================
    logic new_xnor_128_on; 

    always_comb begin
        // Değişkenleri kendi içinde tanımlıyoruz (çakışma olmaması için)
        logic xnr2_main, xnr2_body, xnr2_back, xnr2_bub, xnr2_i1, xnr2_i2, xnr2_out;
        logic signed [11:0] dx_m2, dy_m2, dx_c2, dy_c2, dx_b2, dy_b2, dx_bub2, dy_bub2;
        logic [23:0] d2_m2, d2_c2, d2_b2, d2_bub2;

        // Resetler (Zorunlu)
        xnr2_main=0; xnr2_body=0; xnr2_back=0; xnr2_bub=0; xnr2_i1=0; xnr2_i2=0; xnr2_out=0; new_xnor_128_on=0;
        dx_m2=0; dy_m2=0; d2_m2=0; dx_c2=0; dy_c2=0; d2_c2=0; dx_b2=0; dy_b2=0; d2_b2=0; dx_bub2=0; dy_bub2=0; d2_bub2=0;

        // BOUNDING BOX: FPGA yorulmasın diye sadece bu alandayken hesaplama yapıyoruz
        if (h_count >= 10'd100 && h_count <= 10'd160 && v_count >= 10'd220 && v_count <= 10'd260) begin
            
            // 1. Ana Kavis (Main Curve) - Merkez: (128, 240)
            dx_m2 = $signed({1'b0, h_count}) - 12'sd128; 
            dy_m2 = $signed({1'b0, v_count}) - 12'sd240;
            d2_m2 = dx_m2*dx_m2 + dy_m2*dy_m2;
            if (d2_m2 <= 24'd100 && h_count >= 10'd128) xnr2_main = 1'b1;

            // 2. İç Boşluk / Gövde (Body) - Merkez: (118, 240)
            dx_c2 = $signed({1'b0, h_count}) - 12'sd118; 
            dy_c2 = $signed({1'b0, v_count}) - 12'sd240;
            d2_c2 = dx_c2*dx_c2 + dy_c2*dy_c2;
            if (h_count >= 10'd118 && h_count <= 10'd128 && v_count >= 10'd230 && v_count <= 10'd250 && d2_c2 > 24'd100) 
                xnr2_body = 1'b1;

            // 3. XNOR'a özel ayrık arka kavis (Back Curve) - Merkez: (117, 240)
            dx_b2 = $signed({1'b0, h_count}) - 12'sd117; 
            dy_b2 = $signed({1'b0, v_count}) - 12'sd240;
            d2_b2 = dx_b2*dx_b2 + dy_b2*dy_b2;
            if (d2_b2 >= 24'd49 && d2_b2 <= 24'd64 && h_count >= 10'd117) 
                xnr2_back = 1'b1;

            // 4. XNOR Yuvarlağı (Bubble) - Merkez: (141, 240)
            dx_bub2 = $signed({1'b0, h_count}) - 12'sd141; 
            dy_bub2 = $signed({1'b0, v_count}) - 12'sd240;
            d2_bub2 = dx_bub2*dx_bub2 + dy_bub2*dy_bub2;
            if (d2_bub2 <= 24'd16) 
                xnr2_bub = 1'b1;

            // 5. Giriş ve Çıkış Pinleri
            if (h_count >= 10'd106 && h_count <= 10'd116 && v_count >= 10'd234 && v_count <= 10'd236) xnr2_i1 = 1'b1;
            if (h_count >= 10'd106 && h_count <= 10'd116 && v_count >= 10'd244 && v_count <= 10'd246) xnr2_i2 = 1'b1;
            if (h_count >= 10'd145 && h_count <= 10'd155 && v_count >= 10'd239 && v_count <= 10'd241) xnr2_out = 1'b1;

            // Boyama sinyalini aktif et
            new_xnor_128_on = (xnr2_main || xnr2_body || xnr2_back || xnr2_bub || xnr2_i1 || xnr2_i2 || xnr2_out);
        end
    end
    
	 // =========================================================================
// YENİ OR GATE (X=256, Y=80) [SAĞA BAKAN]
// =========================================================================
logic new_or_256_on;

always_comb begin
    // Dahili sinyaller
    logic o_semi1, o_semi2, o_body, o_in1, o_in2, o_out;
    logic signed [11:0] dx_o1, dy_o1, dx_o2, dy_o2;
    logic [23:0] d2_o1, d2_o2;

    // Resetler
    o_semi1 = 0; o_semi2 = 0; o_body = 0; o_in1 = 0; o_in2 = 0; o_out = 0; new_or_256_on = 0;
    dx_o1 = 0; dy_o1 = 0; d2_o1 = 0; dx_o2 = 0; dy_o2 = 0; d2_o2 = 0;

    // Bounding Box: Sadece X=230-280, Y=65-95 aralığında hesapla
    if (h_count >= 10'd230 && h_count <= 10'd285 && v_count >= 10'd65 && v_count <= 10'd95) begin
        
        // 1. Ön Kavis (Sağ Yarım Daire) - Merkez: (256, 80)
        dx_o1 = $signed({1'b0, h_count}) - 12'sd256;
        dy_o1 = $signed({1'b0, v_count}) - 12'sd80;
        d2_o1 = dx_o1 * dx_o1 + dy_o1 * dy_o1;
        if (d2_o1 <= 24'd100 && h_count >= 10'd256) o_semi1 = 1'b1;

        // 2. Arka Kavis (Sol Boşluk) - Merkez: (246, 80)
        dx_o2 = $signed({1'b0, h_count}) - 12'sd246;
        dy_o2 = $signed({1'b0, v_count}) - 12'sd80;
        d2_o2 = dx_o2 * dx_o2 + dy_o2 * dy_o2;
        if (d2_o2 <= 24'd100 && h_count >= 10'd246) o_semi2 = 1'b1;

        // 3. Gövde: İki kavisin birleşimi (Arka kavisin olmadığı ama sınırda olan yer)
        if (h_count >= 10'd246 && h_count <= 10'd256 && v_count >= 10'd70 && v_count <= 10'd90 && !o_semi2)
            o_body = 1'b1;

        // 4. Pinler (Girişler ve Çıkış)
        if (h_count >= 10'd238 && h_count <= 10'd248 && v_count >= 10'd74 && v_count <= 10'd76) o_in1 = 1'b1;
        if (h_count >= 10'd238 && h_count <= 10'd248 && v_count >= 10'd84 && v_count <= 10'd86) o_in2 = 1'b1;
        if (h_count >= 10'd266 && h_count <= 10'd276 && v_count >= 10'd79 && v_count <= 10'd81) o_out = 1'b1;

        new_or_256_on = (o_semi1 || o_body || o_in1 || o_in2 || o_out);
    end
end
	 
// =========================================================================
    // MAVİ İŞARETLİ KAPILAR (5 ADET XOR) - OPTİMİZE EDİLMİŞ VERSİYON
    // =========================================================================

    logic xor_b1_on, xor_b2_on, xor_b3_on, xor_b4_on, xor_b5_on;

    // Ortak değişkenler (İsim çakışması önlendi: xb = xor blue)
    logic signed [11:0] dx_xb, dy_xb, dx_xbc, dy_xbc, dx_xbcr, dy_xbcr;
    logic [23:0] dist2_xb, dist2_xbc, dist2_xbcr;

    always_comb begin
        // Bütün sinyallerin başlangıç ataması (Zorunlu)
        xor_b1_on=0; xor_b2_on=0; xor_b3_on=0; xor_b4_on=0; xor_b5_on=0;
        dx_xb=0; dy_xb=0; dist2_xb=24'hFFFFFF;
        dx_xbc=0; dy_xbc=0; dist2_xbc=24'hFFFFFF;
        dx_xbcr=0; dy_xbcr=0; dist2_xbcr=24'hFFFFFF;

        // --- MAVİ 1: XOR (Sol Üst Dikey Çizgi - X=128, Y=100) [SAĞA BAKAN] ---
        if (h_count >= 10'd100 && h_count <= 10'd155 && v_count >= 10'd85 && v_count <= 10'd115) begin
            dx_xb = $signed({1'b0, h_count}) - 12'sd128; dy_xb = $signed({1'b0, v_count}) - 12'sd100;
            dist2_xb = dx_xb*dx_xb + dy_xb*dy_xb;

            dx_xbc = $signed({1'b0, h_count}) - 12'sd118; dy_xbc = $signed({1'b0, v_count}) - 12'sd100;
            dist2_xbc = dx_xbc*dx_xbc + dy_xbc*dy_xbc;

            dx_xbcr = $signed({1'b0, h_count}) - 12'sd117; dy_xbcr = $signed({1'b0, v_count}) - 12'sd100;
            dist2_xbcr = dx_xbcr*dx_xbcr + dy_xbcr*dy_xbcr;

            if (dist2_xb <= 24'd100 && h_count >= 10'd128) xor_b1_on = 1'b1;
            else if (h_count >= 10'd118 && h_count <= 10'd128 && v_count >= 10'd90 && v_count <= 10'd110 && dist2_xbc > 24'd100) xor_b1_on = 1'b1;
            else if (dist2_xbcr >= 24'd49 && dist2_xbcr <= 24'd64 && h_count >= 10'd117) xor_b1_on = 1'b1;
            else if (h_count >= 10'd106 && h_count <= 10'd116 && v_count >= 10'd94 && v_count <= 10'd96) xor_b1_on = 1'b1;
