function automatic logic maze_hit(input logic [9:0] sx, input logic [9:0] sy);
        begin
            maze_hit = 
                // --- Dikey Çizgiler (X sabit, Y aralıklı) ---
                rect_hit(sx, sy, 10'd409, 10'd409, 10'd185, 10'd210) ||
                rect_hit(sx, sy, 10'd409, 10'd409, 10'd255, 10'd325) ||
                rect_hit(sx, sy, 10'd409, 10'd409, 10'd360, 10'd455) ||
                
                rect_hit(sx, sy, 10'd434, 10'd434, 10'd210, 10'd225) ||
                rect_hit(sx, sy, 10'd434, 10'd434, 10'd255, 10'd400) ||
                rect_hit(sx, sy, 10'd434, 10'd434, 10'd430, 10'd480) ||
                
                rect_hit(sx, sy, 10'd459, 10'd459, 10'd185, 10'd295) ||
                rect_hit(sx, sy, 10'd459, 10'd459, 10'd370, 10'd455) ||
                
                rect_hit(sx, sy, 10'd484, 10'd484, 10'd185, 10'd330) ||
                rect_hit(sx, sy, 10'd484, 10'd484, 10'd365, 10'd480) ||
                
                // --- Yatay Çizgiler (Y sabit, X aralıklı) ---
                rect_hit(sx, sy, 10'd434, 10'd459, 10'd185, 10'd185) ||
                rect_hit(sx, sy, 10'd409, 10'd434, 10'd210, 10'd210) ||
                rect_hit(sx, sy, 10'd385, 10'd435, 10'd225, 10'd225) ||
                rect_hit(sx, sy, 10'd385, 10'd410, 10'd255, 10'd255) ||
                rect_hit(sx, sy, 10'd434, 10'd459, 10'd255, 10'd255) ||
                rect_hit(sx, sy, 10'd484, 10'd512, 10'd290, 10'd290) ||
                rect_hit(sx, sy, 10'd459, 10'd484, 10'd330, 10'd330) ||
                rect_hit(sx, sy, 10'd434, 10'd459, 10'd370, 10'd370) ||
                rect_hit(sx, sy, 10'd409, 10'd434, 10'd360, 10'd360) ||
                
                // --- Yeni Eklenen Dışarı Taşma Çizgisi ---
                rect_hit(sx, sy, 10'd512, 10'd538, 10'd395, 10'd395);
        end
    endfunction
	 
