            if (v_count >= 10'd200 && v_count <= 10'd205) begin
                if (h_count >= (10'd322 - (v_count - 10'd200)) && h_count <= (10'd322 + (v_count - 10'd200))) up_arrow_on = 1'b1;
            end
        end

        // --- Sağa Bakan Ok (Konum: X=355, Y=240) ---
        if (v_count >= 10'd235 && v_count <= 10'd245) begin
            if (v_count >= 10'd238 && v_count <= 10'd242 && h_count >= 10'd340 && h_count <= 10'd355) right_arrow_on = 1'b1;
            if (h_count >= 10'd355 && h_count <= 10'd360) begin
                if (v_count >= (10'd240 - (10'd360 - h_count)) && v_count <= (10'd240 + (10'd360 - h_count))) right_arrow_on = 1'b1;
            end
        end

        // --- "RUN" Yazısı Lojiği (Sağa bakan okun altı) ---
        if (v_count >= 10'd255 && v_count <= 10'd267 && h_count >= 10'd341 && h_count <= 10'd368) begin
            // 'R' Harfi
            if ((h_count >= 10'd341 && h_count <= 10'd342) || 
                (h_count >= 10'd341 && h_count <= 10'd347 && v_count >= 10'd255 && v_count <= 10'd256) || 
                (h_count >= 10'd341 && h_count <= 10'd347 && v_count >= 10'd261 && v_count <= 10'd262) || 
                (h_count >= 10'd346 && h_count <= 10'd347 && v_count >= 10'd255 && v_count <= 10'd261) || 
                (h_count >= 10'd345 && h_count <= 10'd347 && v_count >= 10'd263 && v_count <= 10'd267)) text_run_on = 1'b1;
            // 'U' Harfi
            if ((h_count >= 10'd351 && h_count <= 10'd352) || 
                (h_count >= 10'd356 && h_count <= 10'd357) || 
                (h_count >= 10'd351 && h_count <= 10'd357 && v_count >= 10'd266 && v_count <= 10'd267)) text_run_on = 1'b1;
            // 'N' Harfi
            if ((h_count >= 10'd361 && h_count <= 10'd362) || 
                (h_count >= 10'd366 && h_count <= 10'd367) || 
                (h_count >= 10'd363 && h_count <= 10'd365 && v_count >= 10'd258 && v_count <= 10'd264)) text_run_on = 1'b1;
        end

        // --- "Q/A" Yazısı Lojiği (Yukarı bakan okun sağı) ---
        if (v_count >= 10'd205 && v_count <= 10'd217 && h_count >= 10'd330 && h_count <= 10'd354) begin
            // 'Q' Harfi (X: 330 - 337)
            if ((h_count >= 10'd330 && h_count <= 10'd331 && v_count >= 10'd206 && v_count <= 10'd215) || // Sol dikey
                (h_count >= 10'd336 && h_count <= 10'd337 && v_count >= 10'd206 && v_count <= 10'd215) || // Sağ dikey
                (h_count >= 10'd332 && h_count <= 10'd335 && v_count >= 10'd205 && v_count <= 10'd206) || // Üst yatay
                (h_count >= 10'd332 && h_count <= 10'd335 && v_count >= 10'd215 && v_count <= 10'd216) || // Alt yatay
                (h_count >= 10'd335 && h_count <= 10'd337 && v_count >= 10'd215 && v_count <= 10'd217))   // Kuyruk
                text_qa_on = 1'b1;

            // '/' İşareti (Slaş) (X: 340 - 344)
            if ((h_count >= 10'd343 && h_count <= 10'd344 && v_count >= 10'd205 && v_count <= 10'd208) ||
                (h_count >= 10'd342 && h_count <= 10'd343 && v_count >= 10'd209 && v_count <= 10'd213) ||
                (h_count >= 10'd340 && h_count <= 10'd341 && v_count >= 10'd214 && v_count <= 10'd217))
                text_qa_on = 1'b1;

            // 'A' Harfi (X: 347 - 354)
            if ((h_count >= 10'd347 && h_count <= 10'd348 && v_count >= 10'd206 && v_count <= 10'd217) || // Sol dikey
                (h_count >= 10'd353 && h_count <= 10'd354 && v_count >= 10'd206 && v_count <= 10'd217) || // Sağ dikey
                (h_count >= 10'd349 && h_count <= 10'd352 && v_count >= 10'd205 && v_count <= 10'd206) || // Üst yatay
                (h_count >= 10'd349 && h_count <= 10'd352 && v_count >= 10'd210 && v_count <= 10'd211))   // Orta yatay
                text_qa_on = 1'b1;
        end
    end

