        rect_hit(square_x + STEP, square_y, 10'd537, 10'd614, 10'd419, 10'd420) ||
        rect_hit(square_x + STEP, square_y, 10'd537, 10'd538, 10'd320, 10'd394) ||
        maze_hit(square_x + STEP, square_y); // Labirent çarpışması

    assign extra_wall_block_left =
        rect_hit(square_x - STEP, square_y, 10'd513, 10'd614, 10'd454, 10'd455) ||
        rect_hit(square_x - STEP, square_y, 10'd613, 10'd614, 10'd320, 10'd419) ||
        rect_hit(square_x - STEP, square_y, 10'd537, 10'd614, 10'd419, 10'd420) ||
        rect_hit(square_x - STEP, square_y, 10'd537, 10'd538, 10'd320, 10'd394) ||
        maze_hit(square_x - STEP, square_y); // Labirent çarpışması

    assign extra_wall_block_down =
        rect_hit(square_x, square_y + STEP, 10'd513, 10'd614, 10'd454, 10'd455) ||
        rect_hit(square_x, square_y + STEP, 10'd613, 10'd614, 10'd320, 10'd419) ||
        rect_hit(square_x, square_y + STEP, 10'd537, 10'd614, 10'd419, 10'd420) ||
        rect_hit(square_x, square_y + STEP, 10'd537, 10'd538, 10'd320, 10'd394) ||
        maze_hit(square_x, square_y + STEP); // Labirent çarpışması

    assign extra_wall_block_up =
        rect_hit(square_x, square_y - STEP, 10'd513, 10'd614, 10'd454, 10'd455) ||
        rect_hit(square_x, square_y - STEP, 10'd613, 10'd614, 10'd320, 10'd419) ||
        rect_hit(square_x, square_y - STEP, 10'd537, 10'd614, 10'd419, 10'd420) ||
        rect_hit(square_x, square_y - STEP, 10'd537, 10'd538, 10'd320, 10'd394) ||
        maze_hit(square_x, square_y - STEP); // Labirent çarpışması
    assign laser1_on = (laser1_phase_count < 2'd2);
    assign laser2_on = (laser2_phase_count < 3'd1);
    assign laser3_on = (laser3_phase_count < 2'd3);

    assign laser1_pixel = laser1_on &&
                          (h_count >= 10'd255 && h_count <= 10'd256) &&
                          (v_count >= 10'd161 && v_count <= 10'd318);
    assign laser2_pixel = laser2_on &&
                          (h_count >= 10'd220 && h_count <= 10'd221) &&
                          (v_count >= 10'd161 && v_count <= 10'd318);
    assign laser3_pixel = laser3_on &&
                          (h_count >= 10'd290 && h_count <= 10'd291) &&
                          (v_count >= 10'd161 && v_count <= 10'd318);
    assign laser_pixel = laser1_pixel || laser2_pixel || laser3_pixel;

    assign laser1_touch_now = laser1_on &&
                              (square_x <= 10'd256) &&
                              (square_x + SQUARE_SIZE - 10'd1 >= 10'd255) &&
                              (square_y <= 10'd318) &&
                              (square_y + SQUARE_SIZE - 10'd1 >= 10'd161);
    assign laser2_touch_now = laser2_on &&
                              (square_x <= 10'd221) &&
                              (square_x + SQUARE_SIZE - 10'd1 >= 10'd220) &&
                              (square_y <= 10'd318) &&
                              (square_y + SQUARE_SIZE - 10'd1 >= 10'd161);
    assign laser3_touch_now = laser3_on &&
                              (square_x <= 10'd291) &&
                              (square_x + SQUARE_SIZE - 10'd1 >= 10'd290) &&
                              (square_y <= 10'd318) &&
                              (square_y + SQUARE_SIZE - 10'd1 >= 10'd161);
    assign laser_touch_now = laser1_touch_now || laser2_touch_now || laser3_touch_now;
    assign laser_hit_start = laser_touch_now && !laser_touch_prev;

    assign timer_running = (state == STATE_GAME) || (state == STATE_GATE_SCREEN);

    vga_timer_laser_controller u_timer_laser_controller (
        .clk(clk_25M),
        .reset(real_reset),
        .timer_running(timer_running),
        .state_gate_screen(state == STATE_GATE_SCREEN),
        .wrong_attempt(gate0_wrong_attempt || gate4_wrong_attempt || gate7_wrong_attempt || gate9_wrong_attempt || gate10_wrong_attempt || gate13_wrong_attempt || gate14_wrong_attempt || gate15_wrong_attempt || gate5_wrong_attempt || gate3_wrong_attempt || gate2_wrong_attempt),
        .laser_hit_start(laser_hit_start),
        .laser_touch_now(laser_touch_now),
        .gate_touch(gate_touch),
        .time_count(time_count),
        .laser1_phase_count(laser1_phase_count),
        .laser2_phase_count(laser2_phase_count),
        .laser3_phase_count(laser3_phase_count),
        .laser_touch_prev(laser_touch_prev),
        .gate_touch_prev(gate_touch_prev),
        .one_sec_tick(one_sec_tick)
    );

    vga_timer_digit_splitter u_timer_digits (
        .value(time_count),
        .hundreds(timer_hundreds),
        .tens(timer_tens),
        .ones(timer_ones)
    );

    vga_timer_digit_splitter u_finish_digits (
        .value(finish_time),
        .hundreds(finish_hundreds),
        .tens(finish_tens),
        .ones(finish_ones)
    );

    vga_timer_digit_splitter u_professor_digits (
        .value(professor_time_count),
        .hundreds(professor_timer_hundreds),
        .tens(professor_timer_tens),
        .ones(professor_timer_ones)
    );

    vga_timer_renderer #(
        .D0_X(D0_X),
        .D1_X(D1_X),
        .D2_X(D2_X),
        .D_Y(D_Y)
    ) u_timer_renderer (
        .px(h_count),
        .py(v_count),
        .hundreds(timer_hundreds),
        .tens(timer_tens),
        .ones(timer_ones),
        .pixel_on(timer_pixel)
    );

    vga_timer_renderer #(
        .D0_X(10'd270),
        .D1_X(10'd298),
        .D2_X(10'd326),
        .D_Y(10'd216)
    ) u_professor_timer_renderer (
        .px(h_count),
        .py(v_count),
        .hundreds(professor_timer_hundreds),
        .tens(professor_timer_tens),
        .ones(professor_timer_ones),
        .pixel_on(professor_timer_pixel)
    );

assign professor_end_text_pixel =
    end_text_line_pixel(h_count, v_count, 10'd113, 10'd120, 2'd0, 5'd23) ||
    end_text_line_pixel(h_count, v_count, 10'd239, 10'd210, 2'd1, 5'd9) ||
    end_text_line_pixel(h_count, v_count, 10'd122, 10'd300, 2'd2, 5'd22);

    // =========================================================================
    // VGA EKRAN BOYAMA VE GÜNCELLEME BLOKLARI
    // =========================================================================

always_ff @(posedge clk_25M or posedge real_reset) begin
    if (real_reset) begin
        square_x      <= 10'd25;
        square_y      <= 10'd435;
        state         <= STATE_INTRO;
        gate_visited  <= 17'd0;
        question_correct <= 1'b0;
        question_wrong   <= 1'b0;
        gate8_opened     <= 1'b0;
        question_gate_idx <= 5'd31;
        professor_screen_active <= 1'b0;
        professor_time_count <= 10'd0;
        sw7_intro_armed <= 1'b0;
        sw7_rules_armed <= 1'b0;
        finish_time <= 10'd0;
    end
    else begin
        case (state)
            STATE_INTRO: begin
                if (frame_tick) begin
                    if (!SW[7])
                        sw7_intro_armed <= 1'b1;
                    if (sw7_intro_armed && SW[7]) begin
                        state <= STATE_RULES;
                        sw7_rules_armed <= 1'b0;
                    end
                end
            end

            STATE_RULES: begin
                if (frame_tick) begin
                    if (SW[7]) begin
                        sw7_rules_armed <= 1'b1;
                    end
                    else if (sw7_rules_armed) begin
                        state <= STATE_GAME;
                        sw7_rules_armed <= 1'b0;
                    end
                end
            end

            STATE_GAME: begin
                if (professor_touch_now) begin
                    finish_time <= time_count;
                    professor_time_count <= time_count;
                    state <= STATE_VICTORY;
                end
                else 
                if (gate_hit_start) begin
                    if (active_gate_idx == 5'd8 && !gate8_opened) begin
                        if (SW[5]) begin
                            state <= STATE_GATE_SCREEN;
                            question_gate_idx <= 5'd8;
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                        else begin
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                    end
                    else if (active_gate_idx == 5'd4 && !gate_visited[4]) begin
                        if (!SW[5]) begin
                            state <= STATE_GATE_SCREEN;
                            question_gate_idx <= 5'd4;
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                        else begin
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                    end
                    else if (active_gate_idx == 5'd5 && !gate_visited[5]) begin
                        question_correct <= 1'b0;
                        question_wrong   <= 1'b0;
                    end
                    else if (active_gate_idx == 5'd7 && !gate_visited[7]) begin
                        if (SW[5]) begin
                            state <= STATE_GATE_SCREEN;
                            question_gate_idx <= 5'd7;
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                        else begin
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                    end
                    else if (active_gate_idx == 5'd9 && !gate_visited[9]) begin
                        if (!SW[5]) begin
                            state <= STATE_GATE_SCREEN;
                            question_gate_idx <= 5'd9;
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                        else begin
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                    end
                    else if (active_gate_idx == 5'd10 && !gate_visited[10]) begin
                        if (SW[5]) begin
                            state <= STATE_GATE_SCREEN;
                            question_gate_idx <= 5'd10;
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                        else begin
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                    end
                    else if (active_gate_idx == 5'd11 && !gate_visited[11]) begin
                        if (SW[5]) begin
                            state <= STATE_GATE_SCREEN;
                            question_gate_idx <= 5'd11;
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                        else begin
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                    end
                    else if (active_gate_idx == 5'd13 && !gate_visited[13]) begin
                        if (SW[5]) begin
                            state <= STATE_GATE_SCREEN;
                            question_gate_idx <= 5'd13;
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                        else begin
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                    end
                    else if (active_gate_idx == 5'd14 && !gate_visited[14]) begin
                        if (!SW[5]) begin
                            state <= STATE_GATE_SCREEN;
                            question_gate_idx <= 5'd14;
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                        else begin
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                    end
                    else if (active_gate_idx == 5'd15 && !gate_visited[15]) begin
                        if (!SW[5]) begin
                            state <= STATE_GATE_SCREEN;
                            question_gate_idx <= 5'd15;
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                        else begin
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                    end
                    else if (active_gate_idx == 5'd16 && !gate_visited[16]) begin
                        question_correct <= 1'b0;
                        question_wrong   <= 1'b0;
                    end
                    else if (active_gate_idx == 5'd3 && !gate_visited[3]) begin
                        if (SW[5]) begin
                            state <= STATE_GATE_SCREEN;
                            question_gate_idx <= 5'd3;
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                        else begin
                            question_correct <= 1'b0;
                            question_wrong   <= 1'b0;
                        end
                    end
                end
                else if (frame_tick) begin
                    square_x <= next_x;
                    square_y <= next_y;
                    if (gate_visited[0]  && !gate_hit_bits[0])  gate_visited[0]  <= 1'b0;
                    if (gate_visited[1]  && !gate_hit_bits[1])  gate_visited[1]  <= 1'b0;
                    if (gate_visited[2]  && !gate_hit_bits[2])  gate_visited[2]  <= 1'b0;
                    if (gate_visited[5]  && !gate_hit_bits[5])  gate_visited[5]  <= 1'b0;
                    if (gate_visited[6]  && !gate_hit_bits[6])  gate_visited[6]  <= 1'b0;
                    if (gate_visited[8]  && !gate_hit_bits[8])  gate_visited[8]  <= 1'b0;
                    if (gate_visited[12] && !gate_hit_bits[12]) gate_visited[12] <= 1'b0;
                end
            end
            STATE_GATE_SCREEN: begin
                if (sw8_edge) begin
                    if ((question_gate_idx == 5'd3  && SW[4:0] == 5'b01000) ||
                        (question_gate_idx == 5'd4  && SW[4:0] == 5'b00010) ||
                        (question_gate_idx == 5'd7  && SW[4:0] == 5'b01000) ||
                        (question_gate_idx == 5'd8  && SW[4:0] == 5'b00100) ||
                        (question_gate_idx == 5'd9  && SW[4:0] == 5'b00100) ||
                        (question_gate_idx == 5'd10 && SW[4:0] == 5'b00100) ||
                        (question_gate_idx == 5'd11 && SW[4:0] == 5'b01000) ||
                        (question_gate_idx == 5'd13 && SW[4:0] == 5'b10000) ||
                        (question_gate_idx == 5'd14 && SW[3:0] == 4'b1011) ||
                        (question_gate_idx == 5'd15 && SW[4:0] == 5'b00010)) begin
                        question_correct <= 1'b1;
                        question_wrong   <= 1'b0;
                        if (question_gate_idx == 5'd3) begin
                            gate_visited[3]  <= 1'b1;
                        end
                        else if (question_gate_idx == 5'd4) begin
                            gate_visited[4]  <= 1'b1;
                        end
                        else if (question_gate_idx == 5'd7) begin
                            gate_visited[7]  <= 1'b1;
                        end
                        else if (question_gate_idx == 5'd8) begin
                            gate8_opened     <= 1'b1;
                            gate_visited[8]  <= 1'b1;
                        end
                        else if (question_gate_idx == 5'd9) begin
                            gate_visited[9]  <= 1'b1;
                        end
                        else if (question_gate_idx == 5'd10) begin
                            gate_visited[10] <= 1'b1;
                        end
                        else if (question_gate_idx == 5'd11) begin
                            gate_visited[11] <= 1'b1;
                        end
                        else if (question_gate_idx == 5'd13) begin
                            gate_visited[13] <= 1'b1;
                        end
                        else if (question_gate_idx == 5'd14) begin
                            gate_visited[14] <= 1'b1;
                        end
                        else if (question_gate_idx == 5'd15) begin
                            gate_visited[15] <= 1'b1;
                        end
                                                question_gate_idx <= 5'd31;
                        state             <= STATE_GAME;
                    end
                    else begin
                        question_correct <= 1'b0;
                        question_wrong   <= 1'b1;
                    end
                end
            end
            STATE_VICTORY: begin
                // Final screen is held until reset/SW9.
            end
            default: state <= STATE_INTRO;
        endcase
    end
end


    vga_tiny_digits_renderer u_tiny_digits_renderer (
        .px(h_count),
        .py(v_count),
        .tiny_digits_on(tiny_digits_on)
    );


    always_ff @(posedge clk_25M or posedge real_reset) begin
        if (real_reset) begin
            VGA_R <= 8'h00;
            VGA_G <= 8'h00;
            VGA_B <= 8'h00;
        end
        else begin
            if (video_on) begin

                        if (state == STATE_INTRO) begin
                            if (intro_text_pixel) begin
                                VGA_R <= 8'hFF;
                                VGA_G <= 8'hD8;
                                VGA_B <= 8'h40;
                            end
                            else if (intro_continue_pixel) begin
                                VGA_R <= 8'h70;
                                VGA_G <= 8'hFF;
                                VGA_B <= 8'hD0;
                            end
                            else begin
                                VGA_R <= 8'h05;
                                VGA_G <= 8'h15;
                                VGA_B <= 8'h30;
                            end
                        end

                        else if (state == STATE_RULES) begin
                            if (rules_start_pixel) begin
                                VGA_R <= 8'h70;
                                VGA_G <= 8'hFF;
                                VGA_B <= 8'hD0;
                            end
                            else if (rules_text_pixel) begin
                                VGA_R <= 8'hFF;
                                VGA_G <= 8'hD8;
                                VGA_B <= 8'h40;
                            end
                            else begin
                                VGA_R <= 8'h05;
                                VGA_G <= 8'h15;
                                VGA_B <= 8'h30;
                            end
                        end

                        else if (state == STATE_VICTORY) begin
                            if (victory_title_pixel) begin
                                VGA_R <= 8'hFF;
                                VGA_G <= 8'hD8;
                                VGA_B <= 8'h40;
                            end
                            else if (victory_main_pixel) begin
                                VGA_R <= 8'h70;
                                VGA_G <= 8'hFF;
                                VGA_B <= 8'hD0;
                            end
                            else if (victory_prof_pixel) begin
                                VGA_R <= 8'hFF;
                                VGA_G <= 8'hFF;
                                VGA_B <= 8'hFF;
                            end
								    else if (victory_restart_pixel) begin
											VGA_R <= 8'hFF;
											VGA_G <= 8'hD7;
											VGA_B <= 8'h00; // sarı
									 end
                            else begin
                                VGA_R <= 8'h05;
                                VGA_G <= 8'h15;
                                VGA_B <= 8'h30;
                            end
                        end

						else if (state == STATE_GATE_SCREEN) begin
							 if (question_correct) begin
								  VGA_R <= 8'h00;
								  VGA_G <= 8'hFF;
								  VGA_B <= 8'h00;
							 end
							 else if (question_wrong) begin
								  if (formula_on) begin
										VGA_R <= 8'hFF;
										VGA_G <= 8'hFF;
										VGA_B <= 8'hFF;
								  end
								  else begin
										VGA_R <= 8'h80;
										VGA_G <= 8'h00;
										VGA_B <= 8'h00;
								  end
							 end
							 else begin
								  if (formula_on) begin
										VGA_R <= 8'hFF;
										VGA_G <= 8'hFF;
										VGA_B <= 8'hFF;
								  end
								  else begin
										VGA_R <= 8'h10;
										VGA_G <= 8'h10;
										VGA_B <= 8'h30;
								  end
							 end
						end

                // 1. OYUNCU KARE (KIRMIZI)
                else if (square_pixel) begin
                    VGA_R <= 8'hFF;
                    VGA_G <= 8'h00;
                    VGA_B <= 8'h00;
                end
                else if (timer_pixel) begin
                    VGA_R <= 8'hFF;
                    VGA_G <= 8'hFF;
                    VGA_B <= 8'hFF;
                end
                else if (bmp_on || text_on) begin
                    VGA_R <= 8'hFF;
                    VGA_G <= 8'hFF;
                    VGA_B <= 8'hFF;
                end
                else if (laser_pixel) begin
                    VGA_R <= 8'hFF;
                    VGA_G <= 8'h00;
                    VGA_B <= 8'h00;
                end
					 // YENİ OKLAR, "RUN" VE "Q/A" YAZILARI (Turuncu)
                else if ((up_arrow_on || right_arrow_on || text_run_on || text_qa_on) && (current_room_visible || expanded_current_room_visible)) begin
                    VGA_R <= 8'hFF; 
                    VGA_G <= 8'h8C; 
                    VGA_B <= 8'h00; 
                end
					 // YENİ LABİRENT DUVARLARI
// YENİ LABİRENT DUVARLARI (Her zaman görünür)
                else if (maze_wall_pixel) begin
                    VGA_R <= 8'hDA; 
                    VGA_G <= 8'hA5; 
                    VGA_B <= 8'h20;
                end
                
                // 2. KAPILARIN TAMAMI (BEYAZ) - Sadece ziyaret edilen odalarda beyaz olur
                else if (all_gate_pixel && (current_room_visible || expanded_current_room_visible)) begin
                    VGA_R <= 8'hFF;
                    VGA_G <= 8'hFF;
                    VGA_B <= 8'hFF;
                end
                else if (tiny_digits_on && (current_room_visible || expanded_current_room_visible)) begin
                    VGA_R <= 8'hFF;
                    VGA_G <= 8'hFF;
                    VGA_B <= 8'hFF;
                end
                
                // 3. GRID (ODALAR) ÇİZGİLERİ (ALTIN SARISI)
                else if (h_count >= 10'd127 && h_count <= 10'd128) begin
                    VGA_R <= 8'hDA; VGA_G <= 8'hA5; VGA_B <= 8'h20;
                end
                else if (h_count >= 10'd255 && h_count <= 10'd256 && !(v_count >= 10'd161 && v_count <= 10'd318)) begin
                    VGA_R <= 8'hDA; VGA_G <= 8'hA5; VGA_B <= 8'h20;
                end
                else if (h_count >= 10'd383 && h_count <= 10'd384) begin
                    VGA_R <= 8'hDA; VGA_G <= 8'hA5; VGA_B <= 8'h20;
                end


                else if (h_count >= 10'd511 && h_count <= 10'd512 && !((v_count >= 10'd455 && v_count <= 10'd479) || (v_count >= 10'd320 && v_count <= 10'd355))) begin
                    VGA_R <= 8'hDA; VGA_G <= 8'hA5; VGA_B <= 8'h20;
                end
                else if (v_count >= 10'd159 && v_count <= 10'd160 &&
                         h_count >= 10'd513 && h_count <= 10'd639) begin
                    VGA_R <= 8'h40;
                    VGA_G <= 8'h47;
                    VGA_B <= 8'h41;
                end
                else if (v_count >= 10'd159 && v_count <= 10'd160) begin
                    VGA_R <= 8'hDA; VGA_G <= 8'hA5; VGA_B <= 8'h20;
                end
                else if (v_count >= 10'd454 && v_count <= 10'd455 &&
                         h_count >= 10'd513 && h_count <= 10'd614) begin
                    VGA_R <= 8'hDA; VGA_G <= 8'hA5; VGA_B <= 8'h20;
                end
                else if (h_count >= 10'd613 && h_count <= 10'd614 &&
                         v_count >= 10'd320 && v_count <= 10'd419) begin
                    VGA_R <= 8'hDA; VGA_G <= 8'hA5; VGA_B <= 8'h20;
                end
                else if (v_count >= 10'd419 && v_count <= 10'd420 &&
                         h_count >= 10'd537 && h_count <= 10'd614) begin
                    VGA_R <= 8'hDA; VGA_G <= 8'hA5; VGA_B <= 8'h20;
                end
                else if (h_count >= 10'd537 && h_count <= 10'd538 &&
                         v_count >= 10'd320 && v_count <= 10'd394) begin
                    VGA_R <= 8'hDA; VGA_G <= 8'hA5; VGA_B <= 8'h20;
                end
                else if (v_count >= 10'd319 && v_count <= 10'd320 && !(h_count >= 10'd385 && h_count <= 10'd510)) begin
                    VGA_R <= 8'hDA; VGA_G <= 8'hA5; VGA_B <= 8'h20;
                end
                
                // 4. ARKAPLAN (GRİ)
                else begin
                    VGA_R <= 8'h40;
                    VGA_G <= 8'h47;
                    VGA_B <= 8'h41;
                end
                
            end
            else begin // Ekran dışı boşluklar (Siyah)
                VGA_R <= 8'h00;
                VGA_G <= 8'h00;
                VGA_B <= 8'h00;
            end
        end
    end

endmodule
